import i18n from "i18next";
import { initReactI18next } from "react-i18next";
import LanguageDetector from "i18next-browser-languagedetector";

i18n
  .use(LanguageDetector)
  .use(initReactI18next)
  .init({
    resources: {
      en: {
        translation: {
          // النواف بار
          nav_home: "Home",
          nav_about: "About Us",
          nav_products: "Products",
          nav_contact: "Contact Us",

          // الصفحة الرئيسية (HomePage)
          hero_title: "Biscoza.. A World of Delicious Taste",
          hero_subtitle:
            "We produce the finest types of biscuits and cakes with natural ingredients to give you happiness in every bite.",
          view_products: "View Products",

          // صفحة من نحن (AboutUs)
          about_title: "Our Story",
          about_text:
            "Biscoza Factory is a leader in the sweets industry, committed to the highest quality standards...",

          // صفحة المنتجات (Products)
          prod_biscuits: "Biscuits Section",
          prod_cake: "Cakes Section",
          more_details: "More Details",
        },
      },
      ar: {
        translation: {
          // النواف بار
          nav_home: "الرئيسية",
          nav_about: "من نحن",
          nav_products: "منتجاتنا",
          nav_contact: "تواصل معنا",

          // الصفحة الرئيسية (HomePage)
          hero_title: "بيسكوزا.. عالم من الطعم اللذيذ",
          hero_subtitle:
            "ننتج أفخر أنواع البسكويت والكيك بمكونات طبيعية لنمنحكم سعادة في كل قضمة.",
          view_products: "عرض المنتجات",

          // صفحة من نحن (AboutUs)
          about_title: "قصتنا",
          about_text:
            "مصنع بيسكوزا رائد في صناعة الحلويات، نلتزم بأعلى معايير الجودة...",

          // صفحة المنتجات (Products)
          prod_biscuits: "قسم البسكويت",
          prod_cake: "قسم الكيك",
          more_details: "تفاصيل أكثر",
        },
      },
    },
    fallbackLng: "ar",
    interpolation: {
      escapeValue: false,
    },
  });

export default i18n;
